+const reloadStateFilename = "reload-state.json"
+
+// transactionalReload coordinates an all-or-nothing reload attempt. The
+// lastGood configuration is only in memory; it is established at startup and
+// after each fully successful reload.
+type transactionalReload struct {
+	mu       sync.RWMutex
+	lastGood *config.Config
+	status   api_v1.ReloadStatus
+	path     string
+	logger   *slog.Logger
+}
+
+func newTransactionalReload(storagePath string, logger *slog.Logger) *transactionalReload {
+	t := &transactionalReload{path: filepath.Join(storagePath, reloadStateFilename), logger: logger}
+	data, err := os.ReadFile(t.path)
+	if err == nil {
+		if err := json.Unmarshal(data, &t.status); err != nil {
+			logger.Warn("Ignoring corrupt transactional reload state", "path", t.path, "err", err)
+			t.status = api_v1.ReloadStatus{}
+		}
+	} else if !os.IsNotExist(err) {
+		logger.Warn("Unable to read transactional reload state", "path", t.path, "err", err)
+	}
+	t.normalizeStatus()
+	return t
+}
+
+func (t *transactionalReload) normalizeStatus() {
+	if t.status.ErrorCategory == "" {
+		t.status.ErrorCategory = "none"
+	}
+	if t.status.AppliedReloaders == nil {
+		t.status.AppliedReloaders = []string{}
+	}
+	if t.status.ReloaderTimingsMS == nil {
+		t.status.ReloaderTimingsMS = map[string]int64{}
+	}
+}
+
+func (t *transactionalReload) Status() api_v1.ReloadStatus {
+	t.mu.RLock()
+	defer t.mu.RUnlock()
+	s := t.status
+	s.AppliedReloaders = append([]string(nil), s.AppliedReloaders...)
+	s.ReloaderTimingsMS = make(map[string]int64, len(t.status.ReloaderTimingsMS))
+	for k, v := range t.status.ReloaderTimingsMS {
+		s.ReloaderTimingsMS[k] = v
+	}
+	return s
+}
+
+func (t *transactionalReload) saveStatus(s api_v1.ReloadStatus) {
+	t.mu.Lock()
+	t.status = s
+	t.normalizeStatus()
+	data, err := json.Marshal(t.status)
+	if err == nil {
+		tmp := t.path + ".tmp"
+		err = os.WriteFile(tmp, data, 0o644)
+		if err == nil {
+			err = os.Rename(tmp, t.path)
+		}
+	}
+	t.mu.Unlock()
+	if err != nil {
+		t.logger.Warn("Unable to persist transactional reload state", "path", t.path, "err", err)
+	}
+}
+
+func (t *transactionalReload) setLastGood(conf *config.Config) {
+	t.mu.Lock()
+	t.lastGood = conf
+	t.mu.Unlock()
+}
+
+func (t *transactionalReload) getLastGood() *config.Config {
+	t.mu.RLock()
+	defer t.mu.RUnlock()
+	return t.lastGood
+}
+
+func (t *transactionalReload) apply(conf *config.Config, rls []reloader, timings map[string]int64, applied *[]string) (string, error) {
+	for _, rl := range rls {
+		start := time.Now()
+		err := rl.reloader(conf)
+		if timings != nil {
+			timings[rl.name] = durationToInt64Millis(time.Since(start))
+		}
+		if err != nil {
+			return rl.name, err
+		}
+		if applied != nil {
+			*applied = append(*applied, rl.name)
+		}
+	}
+	return "", nil
+}
+
+// reload performs a user-visible reload attempt. Load errors deliberately do
+// not trigger rollback because no component has seen the candidate config.
+func (t *transactionalReload) reload(filename string, enableExemplarStorage bool, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), rls ...reloader) error {
+	s := api_v1.ReloadStatus{LastReloadID: time.Now().UTC().Format(time.RFC3339Nano), ErrorCategory: "none", AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]int64{}}
+	conf, err := config.LoadFile(filename, agentMode, t.logger)
+	if err != nil {
+		s.ErrorCategory, s.ErrorMessage = "load_error", err.Error()
+		t.saveStatus(s)
+		callback(false)
+		return fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
+	}
+	if enableExemplarStorage && conf.StorageConfig.ExemplarsConfig == nil {
+		conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
+	}
+
+	failed, err := t.apply(conf, rls, s.ReloaderTimingsMS, &s.AppliedReloaders)
+	if err == nil {
+		t.setLastGood(conf)
+		updateGoGC(conf, t.logger)
+		noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+		s.LastReloadSuccessful = true
+		t.saveStatus(s)
+		callback(true)
+		return nil
+	}
+
+	s.ErrorCategory, s.ErrorMessage, s.FailedReloader = "apply_error", err.Error(), failed
+	if good := t.getLastGood(); good != nil && len(s.AppliedReloaders) > 0 {
+		s.RollbackAttempted = true
+		if rollbackFailed, rollbackErr := t.apply(good, rls, nil, nil); rollbackErr != nil {
+			s.ErrorCategory = "rollback_error"
+			s.ErrorMessage = fmt.Sprintf("apply failed in %s: %v; rollback failed in %s: %v", failed, err, rollbackFailed, rollbackErr)
+		} else {
+			s.RollbackSuccessful = true
+			updateGoGC(good, t.logger)
+			noStepSubqueryInterval.Set(good.GlobalConfig.EvaluationInterval)
+		}
+	}
+	t.saveStatus(s)
+	callback(false)
+	return fmt.Errorf("failed to apply configuration in reloader %q: %w", failed, err)
+}
+
+// loadInitial establishes the rollback point but intentionally does not write
+// an outcome: startup is not a reload attempt.
+func (t *transactionalReload) loadInitial(filename string, enableExemplarStorage bool, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, rls ...reloader) error {
+	conf, err := config.LoadFile(filename, agentMode, t.logger)
+	if err != nil {
+		return fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
+	}
+	if enableExemplarStorage && conf.StorageConfig.ExemplarsConfig == nil {
+		conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
+	}
+	if failed, err := t.apply(conf, rls, nil, nil); err != nil {
+		return fmt.Errorf("failed to apply initial configuration in reloader %q: %w", failed, err)
+	}
+	t.setLastGood(conf)
+	updateGoGC(conf, t.logger)
+	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	return nil
+}
